/*
What Skills are needed for the top-paying jobs?
    - Identify the top 10 jobs with highest salary which are Remote.
    - Focus on job postings with specified salaries (remove nulls).
    - Highlight he top-paying opportuinities for Data related jobs 
    - ADD the specific roles for the jobs
*/

With top_jobs AS (
                    SELECT 
                        Job_ds.job_id,
                        Job_ds.job_title_short,
                        company_dim.name AS company_name,
                        Job_ds.salary_year_avg
                    FROM 
                        job_postings_fact AS Job_ds
                    LEFT JOIN company_dim ON Job_ds.company_id = company_dim.company_id    
                    WHERE 
                        Job_ds.job_location = 'Anywhere' AND 
                        Job_ds.salary_year_avg IS NOT NULL AND
                        Job_ds.job_title_short LIKE '%Data%'
                    ORDER BY Job_ds.salary_year_avg DESC
)
    SELECT 
        top_jobs.job_id,
        top_jobs.job_title_short,
        top_jobs.company_name,
        top_jobs.salary_year_avg,
        req_skills.skills
    FROM top_jobs 
    INNER JOIN (
            SELECT 
                skills_dim.skills,
                skills_dim.skill_id,
                skills_job_dim.job_id
            FROM skills_dim
            LEFT JOIN skills_job_dim ON skills_dim.skill_id = skills_job_dim.skill_id
        ) AS req_skills ON top_jobs.job_id = req_skills.job_id
ORDER BY top_jobs.salary_year_avg DESC


